from datetime import datetime
from pydantic import BaseModel


class MarketSnapshot(BaseModel):
    """
    Deterministically computed from raw market data.
    Exchange-agnostic — no Kalshi-specific fields.
    """
    event: str
    market: str
    outcome: str
    quoted_price: int           # midpoint of yes_bid/yes_ask in cents
    implied_probability: float  # quoted_price / 100
    yes_bid: int
    yes_ask: int
    volume: int
    open_interest: int
    source: str
    timestamp: datetime


class LLMInsight(BaseModel):
    """Fields generated by the LLM."""
    insight_summary: str
    follow_up_actions: list[str]


class InsightReport(BaseModel):
    """Final output combining deterministic data and LLM-generated insight."""
    structured_data: MarketSnapshot
    insight_summary: str
    follow_up_actions: list[str]
